import{_ as i,o as e,c as s,ak as t}from"./chunks/framework.24mNDJkT.js";const o=JSON.parse('{"title":"一、IP 地址分类（Classful Addressing）","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/网络层/IP 地址的分类.md","filePath":"计算机网络/网络层/IP 地址的分类.md","lastUpdated":1775305895000}'),l={name:"计算机网络/网络层/IP 地址的分类.md"};function r(n,a,d,h,p,b){return e(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="一、ip-地址分类-classful-addressing" tabindex="-1">一、IP 地址分类（Classful Addressing） <a class="header-anchor" href="#一、ip-地址分类-classful-addressing" aria-label="Permalink to “一、IP 地址分类（Classful Addressing）”">​</a></h1><h2 id="_1-分类概览" tabindex="-1">1. 分类概览 <a class="header-anchor" href="#_1-分类概览" aria-label="Permalink to “1. 分类概览”">​</a></h2><p>IP 地址（IPv4）共分为 5 类：</p><table tabindex="0"><thead><tr><th>类别</th><th>用途</th><th>是否可分配</th></tr></thead><tbody><tr><td>A 类</td><td>大型网络</td><td>✅</td></tr><tr><td>B 类</td><td>中型网络</td><td>✅</td></tr><tr><td>C 类</td><td>小型网络</td><td>✅</td></tr><tr><td>D 类</td><td>多播（Multicast）</td><td>❌</td></tr><tr><td>E 类</td><td>保留地址</td><td>❌</td></tr></tbody></table><p>👉 实际需要重点掌握：<strong>A / B / C 类</strong></p><hr><h2 id="_2-分类依据-看前几位" tabindex="-1">2. 分类依据（看前几位） <a class="header-anchor" href="#_2-分类依据-看前几位" aria-label="Permalink to “2. 分类依据（看前几位）”">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>二进制前缀</th><th>十进制范围</th></tr></thead><tbody><tr><td>A 类</td><td>0</td><td>1 ~ 126</td></tr><tr><td>B 类</td><td>10</td><td>128 ~ 191</td></tr><tr><td>C 类</td><td>110</td><td>192 ~ 223</td></tr></tbody></table><hr><h1 id="二、网络号-主机号" tabindex="-1">二、网络号 &amp; 主机号 <a class="header-anchor" href="#二、网络号-主机号" aria-label="Permalink to “二、网络号 &amp; 主机号”">​</a></h1><table tabindex="0"><thead><tr><th>类别</th><th>网络号</th><th>主机号</th></tr></thead><tbody><tr><td>A 类</td><td>8 位</td><td>24 位</td></tr><tr><td>B 类</td><td>16 位</td><td>16 位</td></tr><tr><td>C 类</td><td>24 位</td><td>8 位</td></tr></tbody></table><hr><h1 id="三、特殊地址-必须掌握" tabindex="-1">三、特殊地址（必须掌握） <a class="header-anchor" href="#三、特殊地址-必须掌握" aria-label="Permalink to “三、特殊地址（必须掌握）”">​</a></h1><h2 id="_1-网络地址-network-address" tabindex="-1">1. 网络地址（Network Address） <a class="header-anchor" href="#_1-网络地址-network-address" aria-label="Permalink to “1. 网络地址（Network Address）”">​</a></h2><ul><li>特点：<strong>主机号全 0</strong></li><li>作用：表示一个网络</li><li>❌ 不能分配给主机</li></ul><p>例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>192.168.1.0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="_2-广播地址-broadcast-address" tabindex="-1">2. 广播地址（Broadcast Address） <a class="header-anchor" href="#_2-广播地址-broadcast-address" aria-label="Permalink to “2. 广播地址（Broadcast Address）”">​</a></h2><ul><li>特点：<strong>主机号全 1</strong></li><li>作用：向该网络所有主机发送数据</li><li>❌ 不能分配</li></ul><p>例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>192.168.1.255</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="_3-可用主机范围" tabindex="-1">3. 可用主机范围 <a class="header-anchor" href="#_3-可用主机范围" aria-label="Permalink to “3. 可用主机范围”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>192.168.1.1 ~ 192.168.1.254</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 公式：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>可用主机数 = 2^n - 2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>（减去 网络地址 + 广播地址）</p><hr><h1 id="四、示例分析" tabindex="-1">四、示例分析 <a class="header-anchor" href="#四、示例分析" aria-label="Permalink to “四、示例分析”">​</a></h1><h2 id="ip-192-168-1-1" tabindex="-1">IP：192.168.1.1 <a class="header-anchor" href="#ip-192-168-1-1" aria-label="Permalink to “IP：192.168.1.1”">​</a></h2><h3 id="_1-判断类别" tabindex="-1">1. 判断类别 <a class="header-anchor" href="#_1-判断类别" aria-label="Permalink to “1. 判断类别”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>192 → 二进制 110xxxxx → C 类</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-结构" tabindex="-1">2. 结构 <a class="header-anchor" href="#_2-结构" aria-label="Permalink to “2. 结构”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>网络号：192.168.1</span></span>
<span class="line"><span>主机号：1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_3-推导" tabindex="-1">3. 推导 <a class="header-anchor" href="#_3-推导" aria-label="Permalink to “3. 推导”">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>地址</th></tr></thead><tbody><tr><td>网络地址</td><td>192.168.1.0</td></tr><tr><td>广播地址</td><td>192.168.1.255</td></tr><tr><td>可用范围</td><td>192.168.1.1 ~ 192.168.1.254</td></tr></tbody></table><hr><h1 id="五、多播-广播" tabindex="-1">五、多播 &amp; 广播 <a class="header-anchor" href="#五、多播-广播" aria-label="Permalink to “五、多播 &amp; 广播”">​</a></h1><h2 id="_1-单播-unicast" tabindex="-1">1. 单播（Unicast） <a class="header-anchor" href="#_1-单播-unicast" aria-label="Permalink to “1. 单播（Unicast）”">​</a></h2><ul><li>一对一通信</li></ul><h2 id="_2-多播-multicast" tabindex="-1">2. 多播（Multicast） <a class="header-anchor" href="#_2-多播-multicast" aria-label="Permalink to “2. 多播（Multicast）”">​</a></h2><ul><li>一对多（组播）</li><li>使用 <strong>D 类地址</strong></li><li>一个地址 → 一组主机</li></ul><h2 id="_3-广播-broadcast" tabindex="-1">3. 广播（Broadcast） <a class="header-anchor" href="#_3-广播-broadcast" aria-label="Permalink to “3. 广播（Broadcast）”">​</a></h2><ul><li>一对所有</li><li>是多播的特殊情况</li></ul><hr><h1 id="六、各类地址规模" tabindex="-1">六、各类地址规模 <a class="header-anchor" href="#六、各类地址规模" aria-label="Permalink to “六、各类地址规模”">​</a></h1><h2 id="_1-a-类" tabindex="-1">1. A 类 <a class="header-anchor" href="#_1-a-类" aria-label="Permalink to “1. A 类”">​</a></h2><ul><li>网络号：7 位（首位固定为 0）</li></ul><p>👉 网络数量：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2^7 - 2 = 126</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 主机数量：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2^24 - 2 ≈ 1677 万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 范围：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1.0.0.0 ~ 126.255.255.255</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="_2-b-类" tabindex="-1">2. B 类 <a class="header-anchor" href="#_2-b-类" aria-label="Permalink to “2. B 类”">​</a></h2><ul><li>网络号：14 位（前两位固定 10）</li></ul><p>👉 网络数量：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2^14 = 16384</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 主机数量：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2^16 - 2 = 65534</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 范围：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>128.0.0.0 ~ 191.255.255.255</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="_3-c-类" tabindex="-1">3. C 类 <a class="header-anchor" href="#_3-c-类" aria-label="Permalink to “3. C 类”">​</a></h2><ul><li>网络号：21 位（前三位固定 110）</li></ul><p>👉 网络数量：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2^21 ≈ 200 万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 主机数量：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2^8 - 2 = 254</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 范围：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>192.0.0.0 ~ 223.255.255.255</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h1 id="七、特殊说明" tabindex="-1">七、特殊说明 <a class="header-anchor" href="#七、特殊说明" aria-label="Permalink to “七、特殊说明”">​</a></h1><h2 id="_1-为什么-a-类是-1-126" tabindex="-1">1. 为什么 A 类是 1~126？ <a class="header-anchor" href="#_1-为什么-a-类是-1-126" aria-label="Permalink to “1. 为什么 A 类是 1~126？”">​</a></h2><ul><li><code>0.x.x.x</code> → 表示当前网络</li><li><code>127.x.x.x</code> → 回环地址（Loopback）</li></ul><p>典型：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>127.0.0.1 → 本机测试地址</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h1 id="八、分类方式的缺陷-重点" tabindex="-1">八、分类方式的缺陷（重点） <a class="header-anchor" href="#八、分类方式的缺陷-重点" aria-label="Permalink to “八、分类方式的缺陷（重点）”">​</a></h1><h2 id="问题-ip-地址浪费严重" tabindex="-1">问题：<strong>IP 地址浪费严重</strong> <a class="header-anchor" href="#问题-ip-地址浪费严重" aria-label="Permalink to “问题：IP 地址浪费严重”">​</a></h2><h3 id="示例" tabindex="-1">示例： <a class="header-anchor" href="#示例" aria-label="Permalink to “示例：”">​</a></h3><ul><li>公司只有 20 台电脑</li><li>却申请了 C 类（254 个地址）</li></ul><p>👉 浪费 200+ IP</p><hr><h2 id="根本原因" tabindex="-1">根本原因： <a class="header-anchor" href="#根本原因" aria-label="Permalink to “根本原因：”">​</a></h2><p>👉 <strong>网络号 &amp; 主机号位数是固定的</strong></p><table tabindex="0"><thead><tr><th>类别</th><th>主机容量</th></tr></thead><tbody><tr><td>A 类</td><td>超大</td></tr><tr><td>B 类</td><td>很大</td></tr><tr><td>C 类</td><td>较小</td></tr></tbody></table><p>👉 不能灵活分配</p><hr><h1 id="九、解决方案-引出后续知识" tabindex="-1">九、解决方案（引出后续知识） <a class="header-anchor" href="#九、解决方案-引出后续知识" aria-label="Permalink to “九、解决方案（引出后续知识）”">​</a></h1><p>👉 为了解决浪费问题，引入：</p><h3 id="cidr-无分类编址" tabindex="-1"><strong>CIDR（无分类编址）</strong> <a class="header-anchor" href="#cidr-无分类编址" aria-label="Permalink to “CIDR（无分类编址）”">​</a></h3><p>核心思想：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>网络号长度可变（不再固定 A/B/C）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>例如：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>192.168.1.0/26</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 可按需分配 IP</p><hr><h1 id="十、总结-高频考点" tabindex="-1">十、总结（高频考点） <a class="header-anchor" href="#十、总结-高频考点" aria-label="Permalink to “十、总结（高频考点）”">​</a></h1><p>必须掌握：</p><ul><li><p>A/B/C 分类规则</p></li><li><p>网络号 vs 主机号</p></li><li><p>网络地址（全 0）</p></li><li><p>广播地址（全 1）</p></li><li><p>主机数计算公式：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2^n - 2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>IP 分类的缺陷（→ CIDR）</p></li></ul>`,103)])])}const u=i(l,[["render",r]]);export{o as __pageData,u as default};
